import os import pickle
import numpy as np import faiss
from sentence_transformers import SentenceTransformer
class VectorIngester:
def init (self, model_name="paraphrase-multilingual-MiniLM-L12-v2"): self.model = SentenceTransformer(model_name)
self.dimension = 384
self.index = faiss.IndexFlatIP(self.dimension)
def process_and_index(self, chunks, index_path, pkl_path):
texts = [c["text"] for c in chunks]
embeddings = self.model.encode(texts, show_progress_bar=True)
# Apply L2 normalization for cosine similarity faiss.normalize_L2(embeddings) self.index.add(np.array(embeddings, dtype=np.float32))
